import Foundation
import MeridianRuntime

// MARK: - Domain types for ecommerce.merconfig
//
// Hand-written in Phase 1. These will be generated by the compiler in Phase 3.
// All types are Codable so State key-path traversal works via JSON round-trip.

// MARK: - Person

public struct Person: Hashable, Codable, Sendable {
    public var id: String
    public var name: String
    public var email: String
    public var phoneNumber: String

    public init(id: String, name: String, email: String, phoneNumber: String = "") {
        self.id = id
        self.name = name
        self.email = email
        self.phoneNumber = phoneNumber
    }
}

// MARK: - AccountManager

public struct AccountManager: Hashable, Codable, Sendable {
    public var id: String
    public var name: String
    public var email: String

    public init(id: String, name: String, email: String) {
        self.id = id
        self.name = name
        self.email = email
    }
}

// MARK: - Customer

public struct Customer: Hashable, Codable, Sendable {
    public enum Status: String, Hashable, Codable, Sendable {
        case active, suspended, closed
    }
    public enum Tier: String, Hashable, Codable, Sendable {
        case standard, premium, enterprise
    }

    public var id: String
    public var name: String
    public var email: String
    public var phoneNumber: String
    public var status: Status
    public var creditLimit: Money
    public var tier: Tier
    public var signupDate: Date
    public var accountManager: AccountManager

    public init(
        id: String,
        name: String,
        email: String,
        phoneNumber: String = "",
        status: Status = .active,
        creditLimit: Money = Money(amount: 10_000, currency: "USD"),
        tier: Tier = .standard,
        signupDate: Date = Date(),
        accountManager: AccountManager = AccountManager(id: "am-default", name: "Manager", email: "manager@example.com")
    ) {
        self.id = id
        self.name = name
        self.email = email
        self.phoneNumber = phoneNumber
        self.status = status
        self.creditLimit = creditLimit
        self.tier = tier
        self.signupDate = signupDate
        self.accountManager = accountManager
    }
}

// MARK: - Order

public struct Order: Hashable, Codable, Sendable {
    public enum Status: String, Hashable, Codable, Sendable {
        case draft, submitted
        case underReview = "under review"
        case approved
        case onHold = "on hold"
        case fulfilled, cancelled, rejected
    }

    public var id: String
    public var status: Status
    public var totalAmount: Money
    public var placementDate: Date

    public init(
        id: String,
        status: Status = .submitted,
        totalAmount: Money = Money(amount: 250, currency: "USD"),
        placementDate: Date = Date()
    ) {
        self.id = id
        self.status = status
        self.totalAmount = totalAmount
        self.placementDate = placementDate
    }
}

// MARK: - LineItem

public struct LineItem: Hashable, Codable, Sendable {
    public var id: String
    public var quantity: Int
    public var unitPrice: Money

    public init(id: String, quantity: Int, unitPrice: Money) {
        self.id = id
        self.quantity = quantity
        self.unitPrice = unitPrice
    }
}

// MARK: - Invoice

public struct Invoice: Hashable, Codable, Sendable {
    public enum Status: String, Hashable, Codable, Sendable {
        case paid, pending, overdue, disputed
    }
    public var id: String
    public var status: Status
    public var amount: Money
    public var dueDate: Date

    public init(id: String, status: Status, amount: Money, dueDate: Date) {
        self.id = id
        self.status = status
        self.amount = amount
        self.dueDate = dueDate
    }
}

