public enum ValidationVerdict: String, Hashable, Codable, Sendable {
    case valid, invalid
}

public struct ValidationResult: Hashable, Codable, Sendable {
    public var verdict: ValidationVerdict
    public var issues: [String]

    public init(verdict: ValidationVerdict, issues: [String] = []) {
        self.verdict = verdict
        self.issues = issues
    }
}

// MARK: - PaymentResult / PaymentStatus

public enum PaymentStatus: String, Hashable, Codable, Sendable {
    case succeeded, failed
}

public struct PaymentResult: Hashable, Codable, Sendable {
    public var status: PaymentStatus
